mapper.select:
SELECT COUNT(*) FROM board_review 
WHERE board_review_tmdb_movie_id = #{movieId} 
AND board_review_member_id = #{memberId}

select * from (
    select rownum as rnum, b.* from (
        (select 
            br.*,
            (select member_nickname from member where member_id = br.board_review_member_id) as board_review_member_nickname
        from board_review br 
        where board_review_status = 1 
        order by board_review_no desc)b
    )
) where rnum between #{start} and #{end}

select * from (
    select rownum as rnum, b.* from (
        (select 
            *
        from board_review
        where board_review_status = 1
        and board_review_title LIKE '%' || #{keyword} || '%'
        order by board_review_no desc)b
    )
) where rnum between #{pageInfo.start} and #{pageInfo.end}

mapper.update:
UPDATE board_review SET
board_review_title = #{boardReviewTitle},
board_review_content = #{boardReviewContent},
board_review_rating = #{boardReviewRating}
WHERE board_review_no = #{boardReviewNo}

